#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while(t--) {
        int n;
        scanf("%d", &n);
        long long ans = n;
        ans += n;
        ans += (1LL * n * (n-1))/2;
        printf("%lld\n", ans);
    }
    return 0;
}

